settings.custom_liquid:
{%- comment -%}
Loads Garamond (serif) + Univers (sans) and applies them ONLY when the template suffix matches.
Usage examples (pick one):
  • page.garamond-univers
  • product.garamond-univers
Change the IF condition below to match your target page/template.
{%- endcomment -%}

{%- assign enable_override = false -%}
{% comment %}
  Page-specific background color override
{% endcomment %}
<style>
  body {
    background-color: #E3DAC9 !important;
  }
</style>


{%- comment -%}
Target by template suffix (recommended):
  Create a template like: templates/page.garamond-univers.json
  Then this condition will be true only on that page template.
{%- endcomment -%}
{%- if template.suffix == 'garamond-univers' -%}
  {%- assign enable_override = true -%}
{%- endif -%}

{%- comment -%}
(Option B) Target by handle:
  Replace 'my-page-handle' with the desired page handle.
{%- endcomment -%}
{%- if template.name == 'page' and page and page.handle == 'my-page-handle' -%}
  {%- assign enable_override = true -%}
{%- endif -%}

{%- if enable_override -%}
  {%- comment -%}
  Prefer WOFF2 for performance. Put files in:
    • Theme assets → use asset_url
    • Or Content > Files → use file_url
  Replace the filenames below with your actual font file names.
  {%- endcomment -%}

  {%- comment -%}Optional preloads (faster first paint){%- endcomment -%}
  <link rel="preload" href="{{ 'GaramondStandard-Regular.woff2' | asset_url }}" as="font" type="font/woff2" crossorigin>
  <link rel="preload" href="{{ 'Univers-Book.woff2' | asset_url }}" as="font" type="font/woff2" crossorigin>

  <style>
    /* === Load webfonts === */
    @font-face{
      font-family:"GaramondStd";
      src:url("{{ 'GaramondStandard-Regular.woff2' | asset_url }}") format("woff2");
      font-weight:400; font-style:normal; font-display:swap;
    }
    @font-face{
      font-family:"GaramondStd";
      src:url("{{ 'GaramondStandard-Italic.woff2' | asset_url }}") format("woff2");
      font-weight:400; font-style:italic; font-display:swap;
    }
    @font-face{
      font-family:"GaramondStd";
      src:url("{{ 'GaramondStandard-Semibold.woff2' | asset_url }}") format("woff2");
      font-weight:600; font-style:normal; font-display:swap;
    }

    @font-face{
      font-family:"Univers";
      src:url("{{ 'Univers-Book.woff2' | asset_url }}") format("woff2");
      font-weight:400; font-style:normal; font-display:swap;
    }
    @font-face{
      font-family:"Univers";
      src:url("{{ 'Univers-Oblique.woff2' | asset_url }}") format("woff2");
      font-weight:400; font-style:italic; font-display:swap;
    }
    @font-face{
      font-family:"Univers";
      src:url("{{ 'Univers-Bold.woff2' | asset_url }}") format("woff2");
      font-weight:700; font-style:normal; font-display:swap;
    }

    /* === Page-scoped font application ===
       Many OS 2.0 themes (Dawn/Release/etc.) use CSS variables.
       We override both variables *and* direct element fonts for safety.
    */
    :root{
      /* Variable overrides (theme-dependent) */
      --font-heading-family: "GaramondStd", Garamond, "Times New Roman", serif;
      --font-body-family: "Univers", "Helvetica Neue", Arial, sans-serif;
    }

    /* Hard overrides as a fallback (scoped to page root to avoid site-wide changes) */
    /* If this is a section, replace #page-root with that section’s id */
    body{
      font-family: var(--font-body-family) !important;
    }
    h1,h2,h3,h4,h5,h6,
    .h0,.h1,.h2,.h3,.h4,.h5,.h6,
    .heading, .title, .product__title{
      font-family: var(--font-heading-family) !important;
    }

    /* If your theme sets fonts on other wrappers, catch them here: */
    .rte, .prose, .article, .content, .product__info{
      font-family: var(--font-body-family) !important;
    }
  </style>
{%- endif -%}
